func isWorkerRegistryRecord(rec WorkerRecord) bool {
	return rec.ID != "" || rec.Kind != "" || rec.State != ""
}

func (m *WorkerManager) Show(id string) (WorkerRecord, error) {
	m.mu.Lock()
	if handle, ok := m.workers[id]; ok {
		rec := handle.record
		m.mu.Unlock()
		return rec, nil
	}
	m.mu.Unlock()
	return m.readRecord(filepath.Join(m.rootDir, id))
}

// Stop performs a graceful termination of the worker:
//  1. Mark state=stopping and persist so observers see the transition.
//  2. Emit bead.stopped event + release the bead claim (if one is held).
//  3. Send SIGTERM to the worker's process group; escalate to SIGKILL
//     after WatchdogKillGrace if the leader is still alive. Pure-goroutine
//     workers have no PID — ctx cancellation below is the only lever.
//  4. Cancel the worker's context so the loop and in-flight executor exit.
//  5. Mark state=stopped and persist. runWorker preserves this terminal
//     state when it writes its final record.
//
// Stop is idempotent: a second call is a no-op. It returns an error only
// when the worker is unknown to the manager (already exited / never existed).
// stopStaleDiskEntry handles the case where a worker's disk record shows
// state=running but no live goroutine exists (e.g. after a server restart).
// It releases any held bead claim and flips the on-disk state to "stopped".
func (m *WorkerManager) stopStaleDiskEntry(id string) error {
	dir := filepath.Join(m.rootDir, id)
	rec, err := m.readRecord(dir)
	if err != nil {
		return fmt.Errorf("worker not running")
	}
	// Terminal state — nothing left to clean up.
	if rec.State != "running" && rec.State != "stopping" {
		return nil
	}

	now := time.Now().UTC()
	beadID := ""
	if rec.CurrentAttempt != nil {
		beadID = rec.CurrentAttempt.BeadID
	}
	if beadID == "" {
		beadID = rec.CurrentBead
	}
	projectRoot := rec.ProjectRoot
	if projectRoot == "" {
		projectRoot = m.projectRoot
	}

	if beadID != "" {
		store := bead.NewStore(ddxroot.JoinProject(projectRoot))
		body := fmt.Sprintf(
			"worker=%s pid=%d reason=stop-stale",
			id, rec.PID,
		)
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead.stopped",
			Summary:   "stop (stale)",
			Body:      body,
			Actor:     "ddx",
			Source:    "server-workers",
			CreatedAt: now,
		})
		_ = store.Unclaim(beadID)
	}

	rec.State = "stopped"
	rec.Status = "stopped"
	if rec.FinishedAt.IsZero() {
		rec.FinishedAt = now
	}
	rec.Lifecycle = append(rec.Lifecycle, WorkerLifecycleEvent{
		Action:    "stop",
		Actor:     "local-operator",
		Timestamp: now,
		Detail:    fmt.Sprintf("reason=stop-stale pid=%d", rec.PID),
		BeadID:    beadID,
	})
	return m.writeRecord(dir, rec)
}

func (m *WorkerManager) Stop(id string) error {
	m.mu.Lock()
	handle := m.workers[id]
	if handle == nil || handle.cancel == nil {
		m.mu.Unlock()
		// Not in-memory: try to clean up a stale disk record left by a
		// previous server run or an abruptly killed goroutine.
		return m.stopStaleDiskEntry(id)
	}
	if handle.stopped {
		m.mu.Unlock()
		return nil
	}
	handle.stopped = true

	now := time.Now().UTC()
	projectRoot := handle.record.ProjectRoot
	if projectRoot == "" {
		projectRoot = m.projectRoot
	}
	pid := handle.record.PID
	beadID := ""
	if handle.record.CurrentAttempt != nil {
		beadID = handle.record.CurrentAttempt.BeadID
	}
	if beadID == "" {
		beadID = handle.record.CurrentBead
	}
	startedAt := handle.record.StartedAt
	handle.record.State = "stopping"
	handle.record.Status = "stopping"
	handle.record.Lifecycle = append(handle.record.Lifecycle, WorkerLifecycleEvent{
		Action:    "stop",
		Actor:     "local-operator",
		Timestamp: now,
		Detail:    fmt.Sprintf("reason=stop pid=%d", pid),
		BeadID:    beadID,
	})
	dir := filepath.Join(m.rootDir, id)
	transitionSnapshot := handle.record
	cancel := handle.cancel
	m.mu.Unlock()

	_ = m.writeRecord(dir, transitionSnapshot)

	// Release the bead claim first — this is durable and must not be
	// leaked even if the SIGKILL path blocks for the full grace window.
	if beadID != "" {
		store := bead.NewStore(ddxroot.JoinProject(projectRoot))
		runtime := time.Duration(0)
		if !startedAt.IsZero() {
			runtime = now.Sub(startedAt)
		}
		body := fmt.Sprintf(
			"worker=%s runtime=%s pid=%d reason=stop",
			id, runtime.Round(time.Second), pid,
		)
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead.stopped",
			Summary:   "stop",
			Body:      body,
			Actor:     "ddx",
			Source:    "server-workers",
			CreatedAt: now,
		})
		_ = store.Unclaim(beadID)
	}

	// Escalate to the process group if we know the PID.
	_, _, _, grace := m.watchdogDeadlines()
	if pid > 0 {
		terminateProcessGroup(pid, grace)
	}

	// Cancel the worker goroutine so any in-process code sees context.Canceled.
	cancel()

	// Flip in-memory state to the terminal "stopped" label. For real
	// workers, runWorker's final writeRecord (with preservedState) will
	// persist this to disk — we deliberately do not writeRecord here a
	// second time because runWorker may still be mid-finalization and a
	// double-write races the test cleanup. Idle handles (no runWorker)
	// have their state observable in-memory; callers that need disk
	// persistence for those can call writeRecord directly.
	m.mu.Lock()
	handle.record.State = "stopped"
	handle.record.Status = "stopped"
	// Only stamp FinishedAt for handles with no attached runWorker
	// goroutine (logFile is the tell — StartExecuteLoop always sets it).
	// For real workers, runWorker sets FinishedAt after its own cleanup.
	if handle.logFile == nil && handle.record.FinishedAt.IsZero() {
		handle.record.FinishedAt = time.Now().UTC()
		finalSnapshot := handle.record
		m.mu.Unlock()
		_ = m.writeRecord(dir, finalSnapshot)
		return nil
	}
	m.mu.Unlock()
	return nil
}

// ensureWatchdog starts the supervisor goroutine exactly once per manager.
// The goroutine runs until StopWatchdog() is called (or the process exits).
func (m *WorkerManager) ensureWatchdog() {
	m.watchdogOnce.Do(func() {
		go m.watchdogLoop()
	})
}

// StopWatchdog halts the supervisor goroutine. Idempotent; used by tests.
func (m *WorkerManager) StopWatchdog() {
	defer func() { _ = recover() }() // tolerate double-close
	close(m.watchdogStop)
}

// watchdogLoop periodically inspects every registered workerHandle and reaps
// those that have outlived WatchdogDeadline with no phase transition in
// StallDeadline.
func (m *WorkerManager) watchdogLoop() {
	_, _, check, _ := m.watchdogDeadlines()
	ticker := time.NewTicker(check)
	defer ticker.Stop()

	for {
		select {
		case <-m.watchdogStop:
			return
		case <-ticker.C:
			m.watchdogSweep(time.Now().UTC())
		}
	}
}

// watchdogSweep inspects every handle once. Split out from watchdogLoop so
// tests can drive the check deterministically without relying on tickers.
func (m *WorkerManager) watchdogSweep(now time.Time) {
	watchdogDL, stallDL, _, _ := m.watchdogDeadlines()

	type candidate struct {
		id      string
		handle  *workerHandle
		runtime time.Duration
		stalled time.Duration
		beadID  string
		pid     int
	}

	m.mu.Lock()
	var picks []candidate
	for id, h := range m.workers {
		if h == nil || h.reaped {
			continue
		}
		rec := h.record
		if !rec.FinishedAt.IsZero() {
			continue
		}
		if rec.StartedAt.IsZero() {
			continue
		}
		runtime := now.Sub(rec.StartedAt)
		if runtime <= watchdogDL {
			continue
		}
		// Stall check — require an in-flight attempt; a worker that is
		// between beads (CurrentAttempt == nil) has no phase to wedge on.
		if rec.CurrentAttempt == nil {
			continue
		}
		lastPhase := h.lastPhaseTS
		if lastPhase.IsZero() {
			lastPhase = rec.StartedAt
		}
		stalled := now.Sub(lastPhase)
		if stalled <= stallDL {
			continue
		}

		beadID := ""
		if rec.CurrentAttempt != nil {
			beadID = rec.CurrentAttempt.BeadID
		}
		if beadID == "" {
			beadID = rec.CurrentBead
		}

		h.reaped = true
		picks = append(picks, candidate{
			id:      id,
			handle:  h,
			runtime: runtime,
			stalled: stalled,
			beadID:  beadID,
			pid:     rec.PID,
		})
	}
	m.mu.Unlock()

	for _, c := range picks {
		m.reapWorker(c.id, c.handle, c.pid, c.beadID, c.runtime, c.stalled, "watchdog")
	}
}

// reapWorker performs the escalation for a stalled worker:
//  1. Emit bead.reaped event on the bead tracker (if a bead is claimed).
//  2. Release the bead claim (Unclaim → status=open).
//  3. SIGTERM → grace → SIGKILL the worker's process group, if a PID is
//     registered. Fall back to ctx cancellation for pure-goroutine workers.
//  4. Mark the WorkerRecord state=reaped and persist it.
func (m *WorkerManager) reapWorker(id string, handle *workerHandle, pid int, beadID string, runtime, stalled time.Duration, reason string) {
	now := time.Now().UTC()

	m.mu.Lock()
	rec := handle.record
	projectRoot := rec.ProjectRoot
	if projectRoot == "" {
		projectRoot = m.projectRoot
	}
	m.mu.Unlock()

	// 1. Emit the reap event and release the bead claim before killing, so
	//    the claim is not leaked even if the kill blocks for the full grace.
	if beadID != "" {
		store := bead.NewStore(ddxroot.JoinProject(projectRoot))
		body := fmt.Sprintf(
			"worker=%s runtime=%s stalled=%s pid=%d reason=%s",
			id, runtime.Round(time.Second), stalled.Round(time.Second), pid, reason,
		)
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead.reaped",
			Summary:   reason,
			Body:      body,
			Actor:     "ddx-watchdog",
			Source:    "server-workers",
			CreatedAt: now,
		})
		_ = store.Unclaim(beadID)
	}

	// 2. Escalate to the worker process group if we know the PID.
	_, _, _, grace := m.watchdogDeadlines()
	if pid > 0 {
		terminateProcessGroup(pid, grace)
	}

	// 3. Cancel the goroutine so any in-process code sees context.Canceled.
	if handle.cancel != nil {
		handle.cancel()
	}

	// 4. Flip state=reaped and persist. runWorker may still race to
	//    overwrite this with "exited" when it returns; that's fine — the
	//    bead.reaped event plus released claim are the durable record.
	m.mu.Lock()
	handle.record.State = "reaped"
	handle.record.Status = "reaped"
	handle.record.ReapReason = reason
	if handle.record.FinishedAt.IsZero() {
		handle.record.FinishedAt = now
	}
	if handle.record.LastError == "" {
		handle.record.LastError = fmt.Sprintf("watchdog reaped worker after runtime=%s stalled=%s",
			runtime.Round(time.Second), stalled.Round(time.Second))
	}
	dir := filepath.Join(m.rootDir, id)
	snapshot := handle.record
	m.mu.Unlock()

	_ = m.writeRecord(dir, snapshot)
}

func (m *WorkerManager) Logs(id string) (string, string, error) {
	m.mu.Lock()
	if handle, ok := m.workers[id]; ok {
		log := handle.logBuf.String()
		m.mu.Unlock()
		return log, "", nil
	}
	m.mu.Unlock()

	// Fall back to reading from disk for completed workers
	rec, err := m.Show(id)
	if err != nil {
		return "", "", err
	}
	if rec.StdoutPath == "" {
		return "", "", nil
	}
	data, err := os.ReadFile(filepath.Join(m.projectRoot, rec.StdoutPath))
	if err != nil {
		return "", "", err
	}
	return string(data), "", nil
}

// drainProgress reads ProgressEvents from ch and:
//  1. Updates the WorkerRecord's CurrentAttempt, RecentPhases, and LastAttempt fields.
//  2. Broadcasts each event to all active SSE subscribers for the worker.
//
// It runs as a goroutine alongside runWorker; it exits when ch is closed.
func (m *WorkerManager) drainProgress(workerID string, handle *workerHandle, ch <-chan agent.ProgressEvent) {
	const maxRecentPhases = 20

package server

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
)

const (
	workerDesiredStateVersion = 1
	defaultWorkerCount        = 0
	defaultWorkerProfile      = "default"
	defaultWorkerIdleInterval = 30 * time.Second
	defaultRestartBackoff     = 30 * time.Second
	defaultRestartBackoffMax  = 10 * time.Minute
	defaultRestartLimit       = 6
)

// WorkerRestartPolicy controls whether the supervisor should restart
// unexpected exits and how aggressively it may retry.
type WorkerRestartPolicy struct {
	Enabled            bool                 `json:"enabled"`
	MaxRestartsPerHour int                  `json:"max_restarts_per_hour"`
	Backoff            executeloop.Duration `json:"backoff"`
	BackoffMax         executeloop.Duration `json:"backoff_max"`
}

// WorkerDesiredState is the durable desired-state model persisted at
// .ddx/workers/desired.json.
type WorkerDesiredState struct {
	Version      int                   `json:"version"`
	ProjectRoot  string                `json:"project_root"`
	DesiredCount int                   `json:"desired_count"`
	DefaultSpec  ExecuteLoopWorkerSpec `json:"default_spec"`
	Restart      WorkerRestartPolicy   `json:"restart"`
	UpdatedAt    time.Time             `json:"updated_at"`
}

// DefaultWorkerDesiredState returns a sane desired-state skeleton for a
// project. Callers normally override DesiredCount before saving.
func DefaultWorkerDesiredState(projectRoot string) WorkerDesiredState {
	state := WorkerDesiredState{
		Version:      workerDesiredStateVersion,
		ProjectRoot:  projectRoot,
		DesiredCount: defaultWorkerCount,
		DefaultSpec: ExecuteLoopWorkerSpec{
			Mode:         executeloop.ModeWatch,
			IdleInterval: executeloop.Duration{Duration: defaultWorkerIdleInterval},
			Profile:      defaultWorkerProfile,
		},
		Restart: WorkerRestartPolicy{
			Enabled:            true,
			MaxRestartsPerHour: defaultRestartLimit,
			Backoff:            executeloop.Duration{Duration: defaultRestartBackoff},
			BackoffMax:         executeloop.Duration{Duration: defaultRestartBackoffMax},
		},
		UpdatedAt: time.Now().UTC(),
	}
	state.DefaultSpec.ApplyDefaults()
	return state
}

// ApplyDefaults fills in sane defaults without mutating explicit operator
// choices. The project root is injected by the caller so the file can be
// validated independently of where it was loaded from.
func (s *WorkerDesiredState) ApplyDefaults(projectRoot string) {
	if s == nil {
		return
	}
	if s.Version == 0 {
		s.Version = workerDesiredStateVersion
	}
	if s.ProjectRoot == "" {
		s.ProjectRoot = projectRoot
	}
	if s.DefaultSpec.Mode == "" {
		s.DefaultSpec.Mode = executeloop.ModeWatch
	}
	if s.DefaultSpec.Mode == executeloop.ModeWatch && s.DefaultSpec.IdleInterval.Duration == 0 {
		s.DefaultSpec.IdleInterval = executeloop.Duration{Duration: defaultWorkerIdleInterval}
	}
	if s.DefaultSpec.Profile == "" {
		s.DefaultSpec.Profile = defaultWorkerProfile
	}
	s.DefaultSpec.ApplyDefaults()

	if s.Restart.Enabled {
		if s.Restart.MaxRestartsPerHour == 0 {
			s.Restart.MaxRestartsPerHour = defaultRestartLimit
		}
		if s.Restart.Backoff.Duration == 0 {
			s.Restart.Backoff = executeloop.Duration{Duration: defaultRestartBackoff}
		}
		if s.Restart.BackoffMax.Duration == 0 {
			s.Restart.BackoffMax = executeloop.Duration{Duration: defaultRestartBackoffMax}
		}
	}
}

// Validate checks the normalized desired state for internal consistency.
func (s WorkerDesiredState) Validate() error {
	if s.Version != workerDesiredStateVersion {
		return fmt.Errorf("worker desired state: unsupported version %d", s.Version)
	}
	if s.ProjectRoot == "" {
		return fmt.Errorf("worker desired state: project_root is required")
	}
	if s.DesiredCount < 0 {
		return fmt.Errorf("worker desired state: desired_count must be >= 0")
	}
	if s.DefaultSpec.Mode == "" {
		return fmt.Errorf("worker desired state: default_spec.mode is required")
	}
	if err := s.DefaultSpec.Validate(); err != nil {
		return fmt.Errorf("worker desired state: default_spec invalid: %w", err)
	}
	if s.Restart.Enabled {
		if s.Restart.MaxRestartsPerHour <= 0 {
			return fmt.Errorf("worker desired state: restart.max_restarts_per_hour must be > 0 when restart is enabled")
		}
		if s.Restart.Backoff.Duration <= 0 {
			return fmt.Errorf("worker desired state: restart.backoff must be > 0 when restart is enabled")
		}
		if s.Restart.BackoffMax.Duration <= 0 {
			return fmt.Errorf("worker desired state: restart.backoff_max must be > 0 when restart is enabled")
		}
		if s.Restart.Backoff.Duration > s.Restart.BackoffMax.Duration {
			return fmt.Errorf("worker desired state: restart.backoff must not exceed restart.backoff_max")
		}
	}
	if s.UpdatedAt.IsZero() {
		return fmt.Errorf("worker desired state: updated_at is required")
	}
	return nil
}

// WorkerSupervisor reconciles durable desired worker state with the live
// server-owned worker registry.
type WorkerSupervisor struct {
	manager *WorkerManager

	mu               sync.Mutex
	seenTerminals    map[string]time.Time
	blockedTerminals map[string]string
	restartEvents    []time.Time
}

// NewWorkerSupervisor returns a supervisor for the given manager.
func NewWorkerSupervisor(m *WorkerManager) *WorkerSupervisor {
	return &WorkerSupervisor{
		manager:          m,
		seenTerminals:    map[string]time.Time{},
		blockedTerminals: map[string]string{},
	}
}

func (s *WorkerSupervisor) desiredStatePath() string {
	if s == nil || s.manager == nil {
		return ""
	}
	return filepath.Join(s.manager.rootDir, "desired.json")
}

// SaveDesiredState normalizes, validates, and persists the desired worker
// state. UpdatedAt is refreshed on every save.
func (s *WorkerSupervisor) SaveDesiredState(state *WorkerDesiredState) error {
	if s == nil || s.manager == nil {
		return fmt.Errorf("worker supervisor is not configured")
	}
	if state == nil {
		return fmt.Errorf("worker desired state is required")
	}

	state.ApplyDefaults(s.manager.projectRoot)
	state.UpdatedAt = time.Now().UTC()
	if err := state.Validate(); err != nil {
		return err
	}

	if err := os.MkdirAll(s.manager.rootDir, 0o755); err != nil {
		return err
	}
	data, err := json.MarshalIndent(state, "", "  ")
	if err != nil {
		return err
	}
	data = append(data, '\n')
	tmp := s.desiredStatePath() + ".tmp"
	if err := os.WriteFile(tmp, data, 0o644); err != nil {
		return err
	}
	return os.Rename(tmp, s.desiredStatePath())
}

// LoadDesiredState reads and validates the durable desired-state file.
func (s *WorkerSupervisor) LoadDesiredState() (WorkerDesiredState, error) {
	if s == nil || s.manager == nil {
		return WorkerDesiredState{}, fmt.Errorf("worker supervisor is not configured")
	}

	data, err := os.ReadFile(s.desiredStatePath())
	if err != nil {
		return WorkerDesiredState{}, err
	}

	var state WorkerDesiredState
	if err := json.Unmarshal(data, &state); err != nil {
		return WorkerDesiredState{}, err
	}
	if state.ProjectRoot != "" && state.ProjectRoot != s.manager.projectRoot {
		return WorkerDesiredState{}, fmt.Errorf("worker desired state: project_root %q does not match manager root %q", state.ProjectRoot, s.manager.projectRoot)
	}
	state.ApplyDefaults(s.manager.projectRoot)
	if err := state.Validate(); err != nil {
		return WorkerDesiredState{}, err
	}
	return state, nil
}

// Reconcile loads the desired state and brings the worker registry toward it.
func (s *WorkerSupervisor) Reconcile() error {
	return s.ReconcileAt(time.Now().UTC())
}

// ReconcileAt is the deterministic reconciliation entry point used by tests.
func (s *WorkerSupervisor) ReconcileAt(now time.Time) error {
	if s == nil || s.manager == nil {
		return fmt.Errorf("worker supervisor is not configured")
	}

	state, err := s.LoadDesiredState()
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return nil
		}
		return err
	}

	projectRoot := state.ProjectRoot
	if projectRoot == "" {
		projectRoot = s.manager.projectRoot
	}

	active, running, terminals, staleIDs, err := s.snapshotWorkers(projectRoot)
	if err != nil {
		return err
	}

	for _, id := range staleIDs {
		if err := s.manager.stopStaleDiskEntry(id); err != nil {
			return err
		}

		}
	}

	s.recordTerminalHistory(terminals, now)

	if len(active) > state.DesiredCount {
		excess := len(active) - state.DesiredCount
		if err := s.stopNewestExcess(running, excess); err != nil {
			return err
		}
	}

	if len(active) < state.DesiredCount && s.canStartMore(state, now) {
		missing := state.DesiredCount - len(active)
		for i := 0; i < missing; i++ {
			spec := state.DefaultSpec
			spec.ProjectRoot = projectRoot
			if _, err := s.manager.StartExecuteLoop(spec); err != nil {
				return err
			}
		}
	}

	return nil
}

func (s *WorkerSupervisor) snapshotWorkers(projectRoot string) (active []WorkerRecord, running []WorkerRecord, terminals []WorkerRecord, staleIDs []string, err error) {
	if s == nil || s.manager == nil {
		return nil, nil, nil, nil, fmt.Errorf("worker supervisor is not configured")
	}

	entries, err := os.ReadDir(s.manager.rootDir)
	if err != nil {
		return nil, nil, nil, nil, err
	}

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}

		dir := filepath.Join(s.manager.rootDir, entry.Name())
		rec, readErr := s.manager.readRecord(dir)
		if readErr != nil {
			continue
		}
		if rec.Kind != "work" {
			continue
		}
		if rec.ProjectRoot != "" && rec.ProjectRoot != projectRoot {
			continue
		}

		hasHandle := s.manager.hasWorkerHandle(rec.ID)
		switch rec.State {
		case "running", "stopping":
			if !hasHandle {
				staleIDs = append(staleIDs, rec.ID)
				continue
			}
			active = append(active, rec)
			if rec.State == "running" {
				running = append(running, rec)
			}
		default:
			terminals = append(terminals, rec)
		}
	}

	sort.Slice(active, func(i, j int) bool {
		if active[i].StartedAt.Equal(active[j].StartedAt) {
			return active[i].ID > active[j].ID
		}
		return active[i].StartedAt.After(active[j].StartedAt)
	})
	sort.Slice(running, func(i, j int) bool {
		if running[i].StartedAt.Equal(running[j].StartedAt) {
			return running[i].ID > running[j].ID
		}
		return running[i].StartedAt.After(running[j].StartedAt)
	})

	return active, running, terminals, staleIDs, nil
}

func (s *WorkerSupervisor) recordTerminalHistory(terminals []WorkerRecord, now time.Time) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if len(terminals) == 0 {
		return
	}

	if s.seenTerminals == nil {
		s.seenTerminals = map[string]time.Time{}
	}
	if s.blockedTerminals == nil {
		s.blockedTerminals = map[string]string{}
	}

	for _, rec := range terminals {
		if _, seen := s.seenTerminals[rec.ID]; seen {
			continue
		}
		s.seenTerminals[rec.ID] = now
		if isExpectedTerminalWorker(rec) {
			continue
		}
		if isRestartBlockedWorker(rec) {
			s.blockedTerminals[rec.ID] = firstNonEmpty(
				rec.ReapReason,
				rec.Status,
				rec.LastError,
				rec.Error,
				rec.State,
			)
			continue
		}
		ts := rec.FinishedAt
		if ts.IsZero() {
			ts = rec.StartedAt
		}
		if ts.IsZero() {
			ts = now
		}
		s.restartEvents = append(s.restartEvents, ts)
	}

	s.restartEvents = pruneTimeWindow(s.restartEvents, now, time.Hour)
}

func (s *WorkerSupervisor) stopNewestExcess(running []WorkerRecord, excess int) error {
	if excess <= 0 {
		return nil
	}

	limit := excess
	if len(running) < limit {
		limit = len(running)
	}
	for i := 0; i < limit; i++ {
		if err := s.manager.Stop(running[i].ID); err != nil {
			return err
		}
	}
	return nil
}

func (s *WorkerSupervisor) canStartMore(state WorkerDesiredState, now time.Time) bool {
	s.mu.Lock()
	defer s.mu.Unlock()

	if len(s.blockedTerminals) > 0 {
		return false
	}

	events := pruneTimeWindow(s.restartEvents, now, time.Hour)
	s.restartEvents = events
	if !state.Restart.Enabled {
		return len(events) == 0
	}
	if len(events) == 0 {
		return true
	}
	if len(events) > state.Restart.MaxRestartsPerHour {
		return false
	}
	delay := restartBackoffDelay(state.Restart, len(events))
	last := events[0]
	for _, ts := range events[1:] {
		if ts.After(last) {
			last = ts
		}
	}
	return !now.Before(last.Add(delay))
}

func restartBackoffDelay(policy WorkerRestartPolicy, recentEvents int) time.Duration {
	delay := policy.Backoff.Duration
	if delay <= 0 {
		return 0
	}
	if recentEvents <= 1 {
		if policy.BackoffMax.Duration > 0 && delay > policy.BackoffMax.Duration {
			return policy.BackoffMax.Duration
		}
		return delay
	}

	shift := recentEvents - 1
	for shift > 0 {
		if delay > time.Duration(1<<62) {
			delay = policy.BackoffMax.Duration
			break
		}
		delay *= 2
		shift--
		if policy.BackoffMax.Duration > 0 && delay >= policy.BackoffMax.Duration {
			delay = policy.BackoffMax.Duration
			break
		}
	}
	if policy.BackoffMax.Duration > 0 && delay > policy.BackoffMax.Duration {
		delay = policy.BackoffMax.Duration
	}
	return delay
}

func pruneTimeWindow(times []time.Time, now time.Time, window time.Duration) []time.Time {
	if window <= 0 || len(times) == 0 {
		return append([]time.Time(nil), times...)
	}
	cutoff := now.Add(-window)
	out := make([]time.Time, 0, len(times))
	for _, ts := range times {
		if ts.Before(cutoff) {
			continue
		}
		out = append(out, ts)
	}
	return out
}

func isExpectedTerminalWorker(rec WorkerRecord) bool {
	switch rec.State {
	case "stopped":
		return true
	case "exited":
		switch rec.Status {
		case "success", "no_ready_work":
			return true
		}
	}
	return false
}

func isRestartBlockedWorker(rec WorkerRecord) bool {
	fields := []string{
		rec.ReapReason,
		rec.Status,
		rec.LastError,
		rec.Error,
		rec.State,
	}
	for _, field := range fields {
		lower := strings.ToLower(field)
		if strings.Contains(lower, "operator_attention") ||
			strings.Contains(lower, "dirty_root") ||
			strings.Contains(lower, "dirty-root") ||
			strings.Contains(lower, "dirty root") {
			return true
		}
	}
	return false
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if strings.TrimSpace(v) != "" {
			return v
		}
	}
	return ""
}

func (m *WorkerManager) hasWorkerHandle(id string) bool {
	if m == nil {
		return false
	}
	m.mu.Lock()
	defer m.mu.Unlock()
	_, ok := m.workers[id]
	return ok
}

